namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    #region CalculateTotal – DataRow tests

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0, 50.00, DisplayName = "Multiple items, no tax")]
    [DataRow(25.00, 2, 0.10, 55.00, DisplayName = "Two items, 10% tax")]
    [DataRow(99.99, 3, 0.08, 323.97, DisplayName = "Three items, 8% tax")]
    [DataRow(0.00, 10, 0.20, 0.00, DisplayName = "Zero price yields zero total")]
    [DataRow(15.50, 0, 0.15, 0.00, DisplayName = "Zero quantity yields zero total")]
    [DataRow(100.00, 1, 1.0, 200.00, DisplayName = "100% tax doubles the price")]
    public void CalculateTotal_ValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expectedTotal)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expectedTotal, result, $"Expected {expectedTotal} but got {result}");
    }

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, DisplayName = "Negative unit price throws")]
    [DataRow(10.00, -1, 0.10, DisplayName = "Negative quantity throws")]
    public void CalculateTotal_NegativeInputs_ThrowsArgumentOutOfRangeException(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, 1, -0.01, DisplayName = "Tax rate below 0 throws")]
    [DataRow(10.00, 1, 1.01, DisplayName = "Tax rate above 1 throws")]
    public void CalculateTotal_InvalidTaxRate_ThrowsArgumentOutOfRangeException(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    #endregion

    #region ApplyDiscount – DataRow tests

    [TestMethod]
    [DataRow(100.00, 0.0, 100.00, DisplayName = "0% discount leaves price unchanged")]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% off $100 = $90")]
    [DataRow(200.00, 25.0, 150.00, DisplayName = "25% off $200 = $150")]
    [DataRow(50.00, 50.0, 25.00, DisplayName = "50% off $50 = $25")]
    [DataRow(80.00, 100.0, 0.00, DisplayName = "100% discount yields zero")]
    public void ApplyDiscount_ValidInputs_ReturnsExpectedPrice(
        double price, double discountPercent, double expectedPrice)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expectedPrice, result);
    }

    [TestMethod]
    [DataRow(100.00, -1.0, DisplayName = "Negative discount throws")]
    [DataRow(100.00, 100.01, DisplayName = "Discount over 100% throws")]
    public void ApplyDiscount_InvalidDiscount_ThrowsArgumentOutOfRangeException(
        double price, double discountPercent)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent));
    }

    #endregion

    #region CalculateTotal – DynamicData tests

    [TestMethod]
    [DynamicData(nameof(BulkOrderTestCases), DynamicDataSourceType.Method)]
    public void CalculateTotal_BulkOrders_ReturnsExpectedTotal(
        decimal unitPrice, int quantity, decimal taxRate, decimal expectedTotal)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expectedTotal, result);
    }

    private static IEnumerable<object[]> BulkOrderTestCases()
    {
        // Large quantities
        yield return new object[] { 5.99m, 100, 0.07m, 640.93m };
        yield return new object[] { 1.00m, 1000, 0.05m, 1050.00m };
        yield return new object[] { 0.01m, 10000, 0.0m, 100.00m };

        // Boundary tax rates
        yield return new object[] { 49.99m, 2, 0.0m, 99.98m };
        yield return new object[] { 49.99m, 2, 1.0m, 199.96m };
    }

    #endregion

    #region ApplyDiscount – DynamicData tests

    [TestMethod]
    [DynamicData(nameof(TieredDiscountTestCases), DynamicDataSourceType.Property)]
    public void ApplyDiscount_TieredDiscounts_ReturnsExpectedPrice(
        decimal price, decimal discountPercent, decimal expectedPrice)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expectedPrice, result);
    }

    public static IEnumerable<object[]> TieredDiscountTestCases
    {
        get
        {
            // Simulates tiered loyalty discounts
            yield return new object[] { 500.00m, 5.0m, 475.00m };
            yield return new object[] { 500.00m, 10.0m, 450.00m };
            yield return new object[] { 500.00m, 15.0m, 425.00m };
            yield return new object[] { 500.00m, 20.0m, 400.00m };

            // Edge: very small discount on large price
            yield return new object[] { 9999.99m, 0.01m, 9999.0m };
        }
    }

    #endregion

    #region FormatPrice – DataRow tests

    [TestMethod]
    [DataRow(19.99, "$", "$19.99", DisplayName = "Default USD format")]
    [DataRow(1234.50, "€", "€1234.50", DisplayName = "Euro symbol")]
    [DataRow(0.00, "$", "$0.00", DisplayName = "Zero price formats correctly")]
    [DataRow(9.999, "£", "£10.00", DisplayName = "Rounds to two decimal places")]
    public void FormatPrice_VariousInputs_ReturnsExpectedString(
        double price, string currencySymbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, currencySymbol);

        Assert.AreEqual(expected, result);
    }

    #endregion
}

